        if (d < 0.001) { hit = true; break; }
        if (t > 20.0) break;
        t += /* ??? */;
    }

    vec3 col = hit ? vec3(1.0) : vec3(0.05, 0.05, 0.15);
    fragColor = vec4(col, 1.0);
}

